// v8.0 Parse Perplexity response into individual scene items
const response = items[0].json.choices[0].message.content;

// Field-name-anchored extraction (same as v7.2)
function extractScenes(text) {
  const fieldOrder = ['overlaidText', 'voiceOverText', 'imagePrompt', 'motionDescription'];
  const scenes = [];
  let searchFrom = 0;
  function isWS(ch) { return ch === ' ' || ch === '\n' || ch === '\r' || ch === '\t'; }
  while (true) {
    const firstKey = '"' + fieldOrder[0] + '"';
    const sceneStart = text.indexOf(firstKey, searchFrom);
    if (sceneStart === -1) break;
    const scene = {};
    let pos = sceneStart;
    for (let fi = 0; fi < fieldOrder.length; fi++) {
      const fn = fieldOrder[fi];
      const nextFn = fi < fieldOrder.length - 1 ? fieldOrder[fi + 1] : null;
      const keyPat = '"' + fn + '"';
      const keyPos = text.indexOf(keyPat, pos);
      if (keyPos === -1) break;
      const colonPos = text.indexOf(':', keyPos + keyPat.length);
      const openQuotePos = text.indexOf('"', colonPos + 1);
      const vStart = openQuotePos + 1;
      let vEnd;
      if (nextFn) {
        const nextKeyPat = '"' + nextFn + '"';
        const nextKeyPos = text.indexOf(nextKeyPat, vStart);
        let back = nextKeyPos - 1;
        while (back > vStart && isWS(text[back])) back--;
        if (text[back] === ',') back--;
        while (back > vStart && isWS(text[back])) back--;
        vEnd = back;
      } else {
        const nextScenePos = text.indexOf('"' + fieldOrder[0] + '"'  , vStart);
        const boundary = nextScenePos !== -1 ? nextScenePos : text.length;
        let bracePos = boundary - 1;
        while (bracePos > vStart && text[bracePos] !== '}') bracePos--;
        let back = bracePos - 1;
        while (back > vStart && isWS(text[back])) back--;
        vEnd = back;
      }
      scene[fn] = text.substring(vStart, vEnd);
      pos = vEnd;
    }
    if (scene[fieldOrder[0]] !== undefined) scenes.push(scene);
    searchFrom = pos + 1;
  }
  return scenes;
}

let scenes = [];
let cleanResponse = '';
for (let i = 0; i < response.length; i++) {
  const c = response.charCodeAt(i);
  cleanResponse += (c < 32 && c !== 9 && c !== 10 && c !== 13) ? ' ' : response[i];
}
let jsonText = cleanResponse;
const codeBlockMatch = cleanResponse.match(/```(?:json)?\s*([\s\S]*?)```/);
if (codeBlockMatch) jsonText = codeBlockMatch[1].trim();
const jsonMatch = jsonText.match(/\{[\s\S]*\}/);
if (jsonMatch) jsonText = jsonMatch[0];

try {
  const sceneData = JSON.parse(jsonText);
  scenes = sceneData.scenes || [];
} catch (e) {
  scenes = extractScenes(jsonText);
  if (scenes.length === 0) throw new Error('Failed to parse scenes: ' + e.message);
}
if (scenes.length === 0) throw new Error('No scenes found');

function cleanText(text) {
  if (!text) return '';
  return text.replace(/"/g, "'").replace(/\n/g, " ").replace(/\r/g, " ").replace(/\t/g, " ").replace(/[\u0000-\u001F\u007F-\u009F]/g, "").trim();
}

// Output one item per scene for HTTP Request nodes to process
return scenes.map((scene, index) => ({
  json: {
    sceneNum: index + 1,
    imagePrompt: cleanText(scene.imagePrompt || '') + ', biblical, spiritual, reverent, cinematic lighting, professional photography, ultra-detailed, photorealistic, 8K quality',
    voiceOverText: cleanText(scene.voiceOverText || ''),
    overlaidText: cleanText(scene.overlaidText || 'Scene ' + (index + 1)),
    motionDescription: cleanText(scene.motionDescription || 'Slow cinematic camera movement with natural motion')
  }
}));

// Aggregate all scene results into template variables for JSON2Video
// v8.0 — text-balanced: splits any scene over 55 words at sentence boundary
const allScenes = $('Parse Scenes').all();
const MAX_WORDS = 55;

// Step 1: Collect all scenes
const scenes = [];
for (let i = 0; i < items.length; i++) {
  scenes.push({
    videoUrl: items[i].json.video?.url || items[i].json.data?.video?.url || '',
    voiceOverText: allScenes[i].json.voiceOverText || '',
    overlaidText: allScenes[i].json.overlaidText || ''
  });
}

// Step 2: PAD to 20 scenes
const lastUrl = scenes.length > 0 ? scenes[scenes.length - 1].videoUrl : '';
while (scenes.length < 20) {
  scenes.push({ videoUrl: lastUrl, voiceOverText: '', overlaidText: '' });
}

// Helper: split text at sentence boundary (period+space) near target word count
function splitAtSentence(text, targetWords) {
  let wordCount = 0;
  // Try to find period+space at or after targetWords
  for (let c = 0; c < text.length; c++) {
    if (text[c] === ' ') wordCount++;
    if (wordCount >= targetWords && text[c] === '.' && c + 1 < text.length && text[c + 1] === ' ') {
      return [text.substring(0, c + 1).trim(), text.substring(c + 1).trim()];
    }
  }
  // Fallback: find period+space after 25 words minimum
  wordCount = 0;
  for (let c = 0; c < text.length; c++) {
    if (text[c] === ' ') wordCount++;
    if (wordCount >= 25 && text[c] === '.' && c + 1 < text.length && text[c + 1] === ' ') {
      return [text.substring(0, c + 1).trim(), text.substring(c + 1).trim()];
    }
  }
  // Last resort: hard split at word boundary
  const words = text.split(' ');
  return [words.slice(0, targetWords).join(' '), words.slice(targetWords).join(' ')];
}

// Step 3: Forward pass — split oversized scenes, push overflow forward
for (let i = 0; i < 19; i++) {
  const words = scenes[i].voiceOverText.split(/\s+/).filter(w => w.length > 0);
  if (words.length <= MAX_WORDS) continue;
  const [kept, overflow] = splitAtSentence(scenes[i].voiceOverText, MAX_WORDS);
  scenes[i].voiceOverText = kept;
  if (overflow) {
    const next = scenes[i + 1];
    if (next.voiceOverText.length > 0) {
      next.voiceOverText = overflow + ' ' + next.voiceOverText;
    } else {
      next.voiceOverText = overflow;
      next.videoUrl = scenes[i].videoUrl;
      next.overlaidText = scenes[i].overlaidText;
    }
  }
}

// Step 4: Handle scene 20 overflow — push backward into scene 19
const words20 = scenes[19].voiceOverText.split(/\s+/).filter(w => w.length > 0);
if (words20.length > MAX_WORDS) {
  const [kept, overflow] = splitAtSentence(scenes[19].voiceOverText, MAX_WORDS);
  scenes[19].voiceOverText = kept;
  if (overflow) {
    // Prepend overflow to scene 19 (index 18) — it becomes a longer scene 19
    scenes[18].voiceOverText = scenes[18].voiceOverText + ' ' + overflow;
  }
}

// Step 4b: Backfill empty scenes — if voiceOverText is empty, split from previous scene
for (let i = 1; i < 20; i++) {
  if (scenes[i].voiceOverText.trim().length === 0) {
    // Find the nearest previous scene with text to split
    for (let j = i - 1; j >= 0; j--) {
      const prevWords = scenes[j].voiceOverText.split(/\s+/).filter(w => w.length > 0);
      if (prevWords.length >= 10) {
        const [kept, overflow] = splitAtSentence(scenes[j].voiceOverText, Math.floor(prevWords.length / 2));
        scenes[j].voiceOverText = kept;
        scenes[i].voiceOverText = overflow;
        if (!scenes[i].overlaidText) {
          // Generate overlaid text from first few words
          const oWords = overflow.split(/\s+/).slice(0, 5).join(' ');
          scenes[i].overlaidText = oWords.replace(/[.,;:!?]+$/, '');
        }
        break;
      }
    }
  }
}

// Step 5: Build template variables
const templateVariables = {};
for (let i = 0; i < 20; i++) {
  const num = i + 1;
  templateVariables['scene' + num + '_videoUrl'] = scenes[i].videoUrl;
  templateVariables['scene' + num + '_voiceOverText'] = scenes[i].voiceOverText;
  templateVariables['scene' + num + '_overlaidText'] = scenes[i].overlaidText;
}
templateVariables.totalScenes = items.length;

// Debug: word counts per scene
const wordCounts = {};
for (let i = 0; i < 20; i++) {
  wordCounts['scene' + (i+1)] = scenes[i].voiceOverText.split(/\s+/).filter(w => w.length > 0).length;
}

return [{
  json: {
    templateVariables: templateVariables,
    totalScenes: items.length,
    debugInfo: {
      timestamp: new Date().toISOString(),
      version: 'v8.0 - Text-balanced (max 55 words/scene)',
      scenesGenerated: items.length,
      scenesPadded: Math.max(0, 20 - items.length),
      wordCounts: wordCounts
    }
  }
}];
